  hostname: store,
  path: '/admin/api/2024-04/graphql.json',
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'X-Shopify-Access-Token': token,
    'Content-Length': Buffer.byteLength(data)
  }
};

