      let totalBowls = 0;
      let dailyMap = {};
      let productMap = {};
      orders.forEach(e => {
        const o = e.node;
        const date = o.createdAt.substring(0, 10);
        const revenue = parseFloat(o.totalPriceSet.shopMoney.amount);
