        dailyMap[date].orders++;
        dailyMap[date].revenue += revenue;
        o.lineItems.edges.forEach(li => {
          const item = li.node;
          const title = item.title;
          const qty = item.quantity;
          if (!title.toLowerCase().includes('桐箱') && !title.toLowerCase().includes('紙袋')) {
            totalBowls += qty;
          }
          if (!productMap[title]) productMap[title] = { qty: 0, revenue: 0 };
          productMap[title].qty += qty;
          productMap[title].revenue += qty * parseFloat(item.variant?.price || 0);
        });
      });
      console.log('Total revenue:', totalRevenue.toFixed(0));
      console.log('Total bowls (excl packaging):', totalBowls);
      console.log('Daily breakdown:');
